package com.example.tools;

public final class ListRepoFiles {
  public static void main(java.lang.String[] args) {
    java.io.File root = new java.io.File(args.length > 0 ? args[0] : ".");
    java.util.List<java.io.File> files = org.machanism.machai.project.layout.ProjectLayout.findFiles(root);
    for (java.io.File f : files) {
      if (f.isFile()) {
        java.lang.System.out.println(f.getPath());
      }
    }
  }
}
